import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip, ZoomControl } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filter, setFilter] = useState("All");

  // Fetch buses every 5 seconds
  const fetchBuses = async () => {
    try {
      const res = await fetch("http://127.0.0.1:8000/buses");
      const data = await res.json();
      setBuses(data.buses || []);
    } catch (err) {
      console.error("Failed to fetch buses:", err);
    }
  };

  useEffect(() => {
    fetchBuses();
    const interval = setInterval(fetchBuses, 5000);
    return () => clearInterval(interval);
  }, []);

  // Count running vs ghost buses
  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status === "Ghost").length;

  // Apply filter
  const filteredBuses =
    filter === "All"
      ? buses
      : buses.filter((b) => (filter === "Running" ? b.status === "Running" : b.status === "Ghost"));

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Filter dropdown - top-left, shifted to avoid zoom buttons */}
      <div
        style={{
          position: "absolute",
          top: 12,   // shifted further down to avoid zoom
          left: 50,
          background: "rgba(255,255,255,0.95)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        <label>
          Show:{" "}
          <select value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Running">Running</option>
            <option value="Ghost">Ghost</option>
          </select>
        </label>
      </div>

      {/* Bus count at bottom-left */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount}
      </div>

      <MapContainer
        center={[40.7128, -74.006]} // NYC center
        zoom={12}
        style={{ height: "100%", width: "100%" }}
        zoomControl={false}  // disable default zoom control to place custom
      >
        <ZoomControl position="topleft" />

        {/* Light basemap */}
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {filteredBuses.map((bus) => (
          <CircleMarker
            key={bus.id + bus.lat + bus.lon}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={bus.status === "Running" ? "green" : "red"}
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Feed:</strong> {bus.feed} <br />
                <strong>Status:</strong> {bus.status} <br />
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
